package com.goalmoney.personal;
import android.content.*;import android.graphics.*;import android.view.*;import java.text.*;import java.util.*;
public class AssetChartView extends View {private DataStore store;private final Paint p=new Paint(Paint.ANTI_ALIAS_FLAG);public AssetChartView(Context c){super(c);}public void setStore(DataStore s){store=s;invalidate();}@Override protected void onDraw(Canvas c){super.onDraw(c);if(store==null)return;List<Long> vals=new ArrayList<>();List<String> labels=new ArrayList<>();Calendar now=Calendar.getInstance();long current=store.total();Map<String,Long> net=new HashMap<>();for(Models.Tx t:store.txs){long d="income".equals(t.type)?t.amount:"expense".equals(t.type)?-t.amount:0;net.put(t.date,net.getOrDefault(t.date,0L)+d);}long cursor=current;for(int i=0;i<7;i++){Calendar day=(Calendar)now.clone();day.add(Calendar.DAY_OF_YEAR,-i);String key=new SimpleDateFormat("yyyy-MM-dd",Locale.US).format(day.getTime());vals.add(0,cursor);labels.add(0,new SimpleDateFormat("dd/MM",Locale.US).format(day.getTime()));cursor-=net.getOrDefault(key,0L);}long min=Collections.min(vals),max=Collections.max(vals);if(max==min)max=min+1;float left=45,right=getWidth()-25,top=32,bottom=getHeight()-55,step=(right-left)/6f;p.setColor(Color.rgb(232,237,245));p.setStrokeWidth(2);for(int i=0;i<5;i++){float y=top+(bottom-top)*i/4;c.drawLine(left,y,right,y,p);}Path path=new Path();p.setColor(Color.rgb(11,87,208));p.setStrokeWidth(6);p.setStyle(Paint.Style.STROKE);for(int i=0;i<vals.size();i++){float x=left+i*step,y=bottom-(vals.get(i)-min)*(bottom-top)/(max-min);if(i==0)path.moveTo(x,y);else path.lineTo(x,y);}c.drawPath(path,p);p.setStyle(Paint.Style.FILL);for(int i=0;i<vals.size();i++){float x=left+i*step,y=bottom-(vals.get(i)-min)*(bottom-top)/(max-min);c.drawCircle(x,y,7,p);}p.setColor(Color.rgb(123,135,157));p.setTextSize(19);p.setTextAlign(Paint.Align.CENTER);for(int i=0;i<labels.size();i++)c.drawText(labels.get(i),left+i*step,getHeight()-18,p);}}
